// ChartPanel.jsx
import { useEffect, useRef } from 'react'
import { createChart, ColorType } from 'lightweight-charts'

export default function ChartPanel({ bars, signals }) {
  const chartContainerRef = useRef(null)
  const chartRef = useRef(null)
  const seriesRef = useRef(null)

  // Initialize chart
  useEffect(() => {
    if (!chartContainerRef.current) return

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: '#131722' },
        textColor: '#d1d4dc',
      },
      grid: {
        vertLines: { color: '#1e222d' },
        horzLines: { color: '#1e222d' },
      },
      width: chartContainerRef.current.clientWidth,
      height: 500,
      timeScale: {
        timeVisible: true,
        secondsVisible: false,
      },
      // Candle ke top/bottom se marker ka gap control karta hai
      rightPriceScale: {
        scaleMargins: {
          top: 0.15,    // jitna kam value, utna hi upar wala marker paas aayega
          bottom: 0.15, // jitna kam value, utna hi neeche wala marker paas aayega
        },
      },
    })

    const candleSeries = chart.addCandlestickSeries({
      upColor: '#26a69a',
      downColor: '#ef5350',
      borderVisible: false,
      wickUpColor: '#26a69a',
      wickDownColor: '#ef5350',
    })

    chartRef.current = chart
    seriesRef.current = candleSeries

    const handleResize = () => {
      chart.applyOptions({ width: chartContainerRef.current.clientWidth })
    }
    window.addEventListener('resize', handleResize)

    return () => {
      window.removeEventListener('resize', handleResize)
      chart.remove()
    }
  }, [])

  // Update candle data
  useEffect(() => {
    if (!seriesRef.current || !bars?.length) return

    const formatted = bars.map(b => ({
      time: b.time,
      open: b.open,
      high: b.high,
      low: b.low,
      close: b.close,
    }))

    seriesRef.current.setData(formatted)
  }, [bars])

  // Update markers (BUY/SELL/CLOSE)
  useEffect(() => {
    if (!seriesRef.current || !signals?.length) return

    const markers = signals
      .map(sig => {
        const bar = bars[sig.barIndex]
        if (!bar) return null

        if (sig.type === 'buy') {
          return {
            time: bar.time,
            position: 'belowBar',   // candle ke neeche, close waale side
            color: '#00e676',
            shape: 'arrowUp',
            text: 'BUY',
            size: 1,                // marker ka size chhota rakhega, isse "paas" dikhega
          }
        }

        if (sig.type === 'sell') {
          return {
            time: bar.time,
            position: 'aboveBar',   // candle ke upar, close waale side
            color: '#ff5252',
            shape: 'arrowDown',
            text: 'SELL',
            size: 1,
          }
        }

        if (sig.type === 'close') {
          return {
            time: bar.time,
            position: 'inBar',      // candle ke bilkul upar center me
            color: '#9e9e9e',
            shape: 'circle',
            text: sig.label || 'CLOSE',
            size: 1,
          }
        }

        return null
      })
      .filter(Boolean)
      // agar ek hi time pe multiple markers ho to time ke hisaab se sort zaroori hai
      .sort((a, b) => a.time - b.time)

    seriesRef.current.setMarkers(markers)
  }, [signals, bars])

  return (
    <div
      ref={chartContainerRef}
      style={{ width: '100%', height: '500px' }}
    />
  )
}

