// ─── 1. Calculate Indicators ────────────────────────────────────
const ema20  = ta.ema(close, 20)
const ema50  = ta.ema(close, 50)
const ema200 = ta.ema(close, 200)
const adx    = ta.adx(14)
const atr    = ta.atr(14)

// ─── 2. State Management Variables ──────────────────────────────
let inPosition = false
let direction  = "" // "BUY" | "SELL"
let entryPrice = 0
let stopLoss   = 0
let target1    = 0
let target2    = 0
let tp1Hit     = false
let lastSignal = 0  // 1 = Buy, -1 = Sell, 0 = None

// ─── 3. Strategy Backtest Loop ──────────────────────────────────
for (let i = 200; i < bars.length; i++) {

  if (inPosition) {
    // ─── BUY TRADE MANAGEMENT ───
    if (direction === "BUY") {
      // 1. Check TP1 Hit -> Move SL to Breakeven
      if (!tp1Hit && high[i] >= target1) {
        tp1Hit = true
        stopLoss = entryPrice
        strategy.alert(true, `TP1 Hit at ${target1.toFixed(2)} - SL moved to Breakeven`, i)
      }

      // 2. Trailing SL (only after TP1 is hit)
      if (tp1Hit) {
        const trailSL = close[i] - 1.5 * atr[i]
        stopLoss = Math.max(stopLoss, trailSL) 
      }

      // 3. Check Stop Loss Hit
      if (low[i] <= stopLoss) {
        strategy.close(i, tp1Hit ? "SL Trail Hit" : "SL Hit")
        inPosition = false
        lastSignal = 0

        // Exiting label close to candle low
        chart.drawLabel("exit_" + i, i, low[i], "🔴 EXIT SL", { color: '#131722', textColor: '#ff4d4d', position: 'below' })
        strategy.alert(true, `SL Hit at ${stopLoss.toFixed(2)} - Position Closed`, i)
      } 
      // 4. Check Target 2 (TP2) Hit
      else if (high[i] >= target2) {
        strategy.close(i, "TP2 Hit")
        inPosition = false
        lastSignal = 0

        // Exiting label close to candle high
        chart.drawLabel("exit_" + i, i, high[i], "💚 EXIT TP2", { color: '#131722', textColor: '#34d399', position: 'above' })
        strategy.alert(true, `TP2 Hit at ${target2.toFixed(2)} - Position Closed`, i)
      }
    }

    // ─── SELL TRADE MANAGEMENT ───
    else if (direction === "SELL") {
      // 1. Check TP1 Hit -> Move SL to Breakeven
      if (!tp1Hit && low[i] <= target1) {
        tp1Hit = true
        stopLoss = entryPrice
        strategy.alert(true, `TP1 Hit at ${target1.toFixed(2)} - SL moved to Breakeven`, i)
      }

      // 2. Trailing SL (only after TP1 is hit)
      if (tp1Hit) {
        const trailSL = close[i] + 1.5 * atr[i]
        stopLoss = Math.min(stopLoss, trailSL)
      }

      // 3. Check Stop Loss Hit
      if (high[i] >= stopLoss) {
        strategy.close(i, tp1Hit ? "SL Trail Hit" : "SL Hit")
        inPosition = false
        lastSignal = 0

        // Exiting label close to candle high
        chart.drawLabel("exit_" + i, i, high[i], "🔴 EXIT SL", { color: '#131722', textColor: '#ff4d4d', position: 'above' })
        strategy.alert(true, `SL Hit at ${stopLoss.toFixed(2)} - Position Closed`, i)
      } 
      // 4. Check Target 2 (TP2) Hit
      else if (low[i] <= target2) {
        strategy.close(i, "TP2 Hit")
        inPosition = false
        lastSignal = 0

        // Exiting label close to candle low
        chart.drawLabel("exit_" + i, i, low[i], "💚 EXIT TP2", { color: '#131722', textColor: '#34d399', position: 'below' })
        strategy.alert(true, `TP2 Hit at ${target2.toFixed(2)} - Position Closed`, i)
      }
    }
  } 

  else {
    // ─── ENTRY TRIGGERS (Flip Logic) ───
    const top    = Math.max(high[i-1], high[i-2])
    const bottom = Math.min(low[i-1], low[i-2])

    const rawBuy  = close[i] > top
    const rawSell = close[i] < bottom

    // BUY Entry
    if (rawBuy && lastSignal !== 1) {
      inPosition = true
      direction  = "BUY"
      entryPrice = close[i]
      stopLoss   = entryPrice - 1.5 * atr[i]
      target1    = entryPrice + 1.5 * atr[i] * 1.5
      target2    = entryPrice + 1.5 * atr[i] * 3.0
      tp1Hit     = false
      lastSignal = 1
      strategy.buy(i, "Buy Breakout")

      // 🟢 BUY Label - candle ke bilkul niche (low[i] par)
      chart.drawLabel("sig_" + i, i, low[i], "🟢 BUY", { color: '#131722', textColor: '#34d399', position: 'below' })
    } 
    // SELL Entry
    else if (rawSell && lastSignal !== -1) {
      inPosition = true
      direction  = "SELL"
      entryPrice = close[i]
      stopLoss   = entryPrice + 1.5 * atr[i]
      target1    = entryPrice - 1.5 * atr[i] * 1.5
      target2    = entryPrice - 1.5 * atr[i] * 3.0
      tp1Hit     = false
      lastSignal = -1
      strategy.sell(i, "Sell Breakout")

      // 🔴 SELL Label - candle ke bilkul upar (high[i] par)
      chart.drawLabel("sig_" + i, i, high[i], "🔴 SELL", { color: '#131722', textColor: '#ff4d4d', position: 'above' })
    }
  }
}

// ─── 4. Live Visual Drawings & Lines ────────────────────────────
if (inPosition) {
  const lastBar  = bars.length - 1
  const startBar = Math.max(0, lastBar - 30)

  chart.drawLine("entry", startBar, entryPrice, lastBar, entryPrice, { color: '#4f9cf9', style: 'solid', extendRight: true })
  chart.drawLine("sl", startBar, stopLoss, lastBar, stopLoss, { color: '#ff4d4d', style: 'dashed', extendRight: true })
  chart.drawLine("tp1", startBar, target1, lastBar, target1, { color: '#fbbf24', style: 'dashed', extendRight: true })
  chart.drawLine("tp2", startBar, target2, lastBar, target2, { color: '#34d399', style: 'solid', extendRight: true })

  const slText = tp1Hit ? (stopLoss === entryPrice ? "SL (BE)" : "SL (Trail)") : "SL"
  chart.drawLabel("entry_lbl", lastBar, entryPrice, "ENTRY", { color: '#1a1f2c', textColor: '#4f9cf9', position: 'right' })
  chart.drawLabel("sl_lbl", lastBar, stopLoss, slText, { color: '#1a1f2c', textColor: '#ff4d4d', position: 'right' })
  chart.drawLabel("tp1_lbl", lastBar, target1, "TP1", { color: '#1a1f2c', textColor: '#fbbf24', position: 'right' })
  chart.drawLabel("tp2_lbl", lastBar, target2, "TP2", { color: '#1a1f2c', textColor: '#34d399', position: 'right' })
}

// ─── 5. Top-Right Dashboard Overlay ─────────────────────────────
const endBar = bars.length - 1

let marketTrend = "SIDEWAYS"
if (ema20[endBar] > ema50[endBar] && ema50[endBar] > ema200[endBar]) {
  marketTrend = "UPTREND"
} else if (ema20[endBar] < ema50[endBar] && ema50[endBar] < ema200[endBar]) {
  marketTrend = "DOWNTREND"
}

let adxStatus = "Ranging"
if (adx[endBar] > 25) {
  adxStatus = "TRENDING"
} else if (adx[endBar] < 20) {
  adxStatus = "RANGING"
}

dashboard.set("Market", marketTrend, marketTrend === "UPTREND" ? "#34d399" : marketTrend === "DOWNTREND" ? "#ff4d4d" : "#94a3b8")
dashboard.set("ADX", `${adx[endBar]?.toFixed(1)} (${adxStatus})`, adx[endBar] > 25 ? "#34d399" : "#94a3b8")
dashboard.set("ATR", atr[endBar]?.toFixed(2), "#4f9cf9")
dashboard.set("SL Mult", "1.5x", "#ffffff")
dashboard.set("RR Ratio", "1:3", "#ffffff")
dashboard.set("Position", inPosition ? `${direction} (${tp1Hit ? 'BE Trailing' : 'Initial'})` : "FLAT", inPosition ? "#34d399" : "#94a3b8")
